#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int V,E; scanf("%d %d", &V, &E);
        long long **best = (long long**)malloc(V*sizeof(long long*));
        for(int i=0;i<V;i++){
            best[i]=(long long*)malloc(V*sizeof(long long));
            for(int j=0;j<V;j++) best[i][j]= (i==j)?0:-1;
        }
        for(int e=0;e<E;e++){
            int u,v; long long w; scanf("%d %d %lld", &u, &v, &w);
            if(w>best[u][v]) best[u][v]=best[v][u]=w;
        }
        for(int k=0;k<V;k++)
            for(int i=0;i<V;i++) if(i!=k)
                for(int j=0;j<V;j++) if(j!=k && i!=j){
                    long long via = best[i][k] < best[k][j] ? best[i][k] : best[k][j];
                    if(via > best[i][j] || best[i][j] == -1) best[i][j]=via;
                }
        for(int i=0;i<V;i++){
            for(int j=0;j<V;j++){
                if(j) printf(" ");
                if(best[i][j] == -1) printf("0");
                else printf("%lld", best[i][j]);
            }
            printf("\n");
        }
        for(int i=0;i<V;i++) free(best[i]);
        free(best);
    }
    return 0;
}

