import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int V = fs.nextInt();
            int E = fs.nextInt();
            long[][] best = new long[V][V];
            for (int i = 0; i < V; i++) {
                for (int j = 0; j < V; j++) {
                    best[i][j] = -1;
                }
            }
            for (int i = 0; i < V; i++) best[i][i] = 0;
            for (int i = 0; i < E; i++) {
                int u = fs.nextInt();
                int v = fs.nextInt();
                long w = fs.nextLong();
                best[u][v] = Math.max(best[u][v], w);
                best[v][u] = Math.max(best[v][u], w);
            }
            for (int k = 0; k < V; k++) {
                for (int i = 0; i < V; i++) if (i != k) {
                    for (int j = 0; j < V; j++) if (j != k && i != j) {
                        long via = Math.min(best[i][k], best[k][j]);
                        if (via > best[i][j] || best[i][j] == -1) best[i][j] = via;
                    }
                }
            }
            for (int i = 0; i < V; i++) {
                for (int j = 0; j < V; j++) {
                    if (j > 0) out.append(' ');
                    if(best[i][j] == -1) out.append('0');
                    else out.append(best[i][j]);
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { return Long.parseLong(next()); }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
    }
}

