import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        V = int(next(it)); E = int(next(it))
        best = [[-1]*V for _ in range(V)]
        for i in range(V):
            best[i][i] = 0
        for _ in range(E):
            u = int(next(it)); v = int(next(it)); w = int(next(it))
            if w > best[u][v]:
                best[u][v] = best[v][u] = w
        for k in range(V):
            bk = best[k]
            for i in range(V):
                if i == k: continue
                bi = best[i]
                bik = bi[k]
                for j in range(V):
                    if j == k or i == j: continue
                    via = bik if bik < bk[j] else bk[j]
                    if via > bi[j] or bi[j] == -1:
                        bi[j] = via
        for i in range(V):
            out_lines.append(' '.join(str(x) if x != -1 else '0' for x in best[i]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

