    const u = Number(data[idx++]);
    const v = Number(data[idx++]);
    const w = Number(data[idx++]);
    if (w > best[u][v]) {
      best[u][v] = best[v][u] = w;
    }
  }
  for (let k = 0; k < V; k++) {
    for (let i = 0; i < V; i++) if (i !== k) {
      for (let j = 0; j < V; j++) if (j !== k && i !== j) {
        const via = Math.min(best[i][k], best[k][j]);
        if (via > best[i][j] || best[i][j] === -1) best[i][j] = via;
